#!/usr/bin/env python3\n"""\nOCI Robot Cloud — Data Flywheel Optimizer\nModels DAgger data collection → fine-tune → eval loop.\nCompares 5 budget-allocation strategies over 10 DAgger iterations.\n\nFlywheel: SR(n) = 0.85 * (1 - exp(-n/800))\nOutput: /tmp/data_flywheel_optimizer.html\nStandalone: stdlib only.\n"""\n\nimport math, json, html\nfrom typing import List, Dict, Any\n\nTAU = 800.0\nSR_MAX = 0.85\nCOST_FINETUNE_PER_1K_DEMOS = 0.43\nTRAINING_STEPS = 5000\nCOST_COLLECT_PER_DEMO = 0.08\nCOST_EVAL_RUN = 0.12\nINITIAL_DEMOS = 99\nINITIAL_SR = 0.05\nITERATIONS = 10\nBUDGET_LIMIT = 50.0\n\ndef sr_from_demos(n): return SR_MAX * (1.0 - math.exp(-n / TAU))\ndef finetune_cost(n, steps=TRAINING_STEPS): return COST_FINETUNE_PER_1K_DEMOS * (n/1000.0) * (steps/5000.0)\ndef collect_cost(n): return COST_COLLECT_PER_DEMO * n\ndef eval_cost(): return COST_EVAL_RUN\n\ndef demos_per_iteration(current_sr, base=100):\n    return max(10, int(base * (1.0 + current_sr / SR_MAX)))\n\nclass SimState:\n    def __init__(self):\n        self.total_demos = INITIAL_DEMOS\n        self.current_sr = INITIAL_SR\n        self.cumulative_cost = 0.0\n        self.finetune_count = 0\n        self.demos_since_last_finetune = 0\n        self.sr_history = [INITIAL_SR]\n        self.cost_history = [0.0]\n        self.demos_history = [INITIAL_DEMOS]\n\n    def collect(self):\n        n = demos_per_iteration(self.current_sr)\n        self.total_demos += n\n        self.demos_since_last_finetune += n\n        self.cumulative_cost += collect_cost(n)\n        return n\n\n    def finetune_and_eval(self):\n        self.cumulative_cost += finetune_cost(self.total_demos) + eval_cost()\n        self.current_sr = sr_from_demos(self.total_demos)\n        self.finetune_count += 1\n        self.demos_since_last_finetune = 0\n\n    def eval_only(self):\n        self.cumulative_cost += eval_cost()\n        self.current_sr = sr_from_demos(self.total_demos)\n\n    def record(self):\n        self.sr_history.append(round(self.current_sr, 4))\n        self.cost_history.append(round(self.cumulative_cost, 4))\n        self.demos_history.append(self.total_demos)\n\ndef simulate_greedy_collect():\n    s = SimState()\n    for i in range(ITERATIONS):\n        s.collect()\n        if i == ITERATIONS - 1: s.finetune_and_eval()\n        else: s.eval_only()\n        s.record()\n    return s\n\ndef simulate_frequent_finetune(freq=50):\n    s = SimState()\n    for _ in range(ITERATIONS):\n        s.collect()\n        if s.demos_since_last_finetune >= freq: s.finetune_and_eval()\n        else: s.eval_only()\n        s.record()\n    return s\n\ndef simulate_optimal_interval(interval=200):\n    s = SimState()\n    for _ in range(ITERATIONS):\n        s.collect()\n        if s.demos_since_last_finetune >= interval: s.finetune_and_eval()\n        else: s.eval_only()\n        s.record()\n    return s\n\ndef simulate_adaptive_threshold(delta_thresh=0.02):\n    s = SimState()\n    prev_sr = s.current_sr\n    for _ in range(ITERATIONS):\n        s.collect()\n        projected = sr_from_demos(s.total_demos)\n        if projected - prev_sr < delta_thresh or s.demos_since_last_finetune >= 300:\n            s.finetune_and_eval(); prev_sr = s.current_sr\n        else: s.eval_only()\n        s.record()\n    return s\n\ndef simulate_budget_constrained(budget=BUDGET_LIMIT):\n    s = SimState()\n    for _ in range(ITERATIONS):\n        s.collect()\n        remaining = budget - s.cumulative_cost\n        if remaining >= finetune_cost(s.total_demos) + eval_cost() and s.demos_since_last_finetune >= 150:\n            s.finetune_and_eval()\n        else: s.eval_only()\n        s.record()\n    return s\n\nSTRATEGY_NAMES = [\"GreedyCollect\",\"FrequentFinetune\",\"OptimalInterval\",\"AdaptiveThreshold\",\"BudgetConstrained\"]\nSTRATEGY_COLORS = [\"#e74c3c\",\"#e67e22\",\"#27ae60\",\"#8e44ad\",\"#2980b9\"]\n\ndef run_all():\n    return {\n        \"GreedyCollect\": simulate_greedy_collect(),\n        \"FrequentFinetune\": simulate_frequent_finetune(),\n        \"OptimalInterval\": simulate_optimal_interval(),\n        \"AdaptiveThreshold\": simulate_adaptive_threshold(),\n        \"BudgetConstrained\": simulate_budget_constrained(),\n    }\n\ndef build_html(results):\n    rows = []\n    for i, name in enumerate(STRATEGY_NAMES):\n        s = results[name]\n        final_sr = s.sr_history[-1]\n        cost = s.cumulative_cost\n        demos = s.total_demos - INITIAL_DEMOS\n        cps = cost / final_sr if final_sr > 0 else 999\n        marker = \" *\" if name == \"OptimalInterval\" else \"\"\n        rows.append(f\"<tr{'  style=background:#e8f5e9' if name==chr(79)+chr(112)+chr(116)+chr(105)+chr(109)+chr(97)+chr(108)+chr(73)+chr(110)+chr(116)+chr(101)+chr(114)+chr(118)+chr(97)+chr(108) else ''}>\"\n                    f\"<td>{name}{marker}</td><td>{final_sr:.2f}</td><td>${cost:.2f}</td>\"\n                    f\"<td>{s.finetune_count}</td><td>{demos}</td><td>${cps:.1f}</td></tr>\")\n    table = (\"<table border=1><tr><th>Strategy</th><th>Final SR</th><th>Cost</th>\"\n             \"<th>Fine-tunes</th><th>Demos</th><th>$/SR</th></tr>\" + \"\".join(rows) + \"</table>\")\n    opt = results[\"OptimalInterval\"]\n    return f\"\"\"<!DOCTYPE html><html><head><title>Data Flywheel Optimizer</title></head><body>\n<h1>OCI Robot Cloud — Data Flywheel Optimizer</h1>\n<p>Flywheel: SR(n) = {SR_MAX} x (1 - exp(-n/{int(TAU)})) | Start: {INITIAL_DEMOS} demos, SR={INITIAL_SR}</p>\n<h2>Strategy Comparison (10 DAgger Iterations)</h2>\n{table}\n<h2>Recommendation: OptimalInterval (200 demos/finetune)</h2>\n<ul>\n<li>Final SR: <b>{opt.sr_history[-1]:.2f}</b></li>\n<li>Total cost: <b>${opt.cumulative_cost:.2f}</b></li>\n<li>Fine-tune count: <b>{opt.finetune_count}</b></li>\n<li>Cost efficiency: <b>${opt.cumulative_cost/opt.sr_history[-1]:.1f} per SR point</b></li>\n<li>Next DAgger: collect 300 more demos, then fine-tune</li>\n<li>Expected SR: <b>{sr_from_demos(opt.total_demos + 300):.2f}</b></li>\n</ul>\n<p><small>Parameters: tau={TAU}, SR_max={SR_MAX}, collect=${COST_COLLECT_PER_DEMO}/demo, finetune=${COST_FINETUNE_PER_1K_DEMOS}/1k-demos</small></p>\n</body></html>\"\"\"\n\ndef main():\n    print(\"OCI Robot Cloud — Data Flywheel Optimizer\")\n    results = run_all()\n    print(f\"{'Strategy':<22} {'Final SR':>9} {'Cost':>10} {'Finetunes':>10} {'Demos':>8}\")\n    print(\"-\" * 65)\n    for name in STRATEGY_NAMES:\n        s = results[name]\n        marker = \" *\" if name == \"OptimalInterval\" else \"\"\n        print(f\"{name+marker:<22} {s.sr_history[-1]:>9.2f} ${s.cumulative_cost:>9.2f} {s.finetune_count:>10} {s.total_demos-INITIAL_DEMOS:>8}\")\n    opt = results[\"OptimalInterval\"]\n    print(f\"\\nOptimalInterval: SR={opt.sr_history[-1]:.2f} at ${opt.cumulative_cost:.2f}\")\n    print(f\"Next DAgger: collect 300 more → expected SR={sr_from_demos(opt.total_demos+300):.2f}\")\n    with open(\"/tmp/data_flywheel_optimizer.html\", \"w\") as f:\n        f.write(build_html(results))\n    print(\"Report: /tmp/data_flywheel_optimizer.html\")\n\nif __name__ == \"__main__\":\n    main()\n